+                f,
+                "insufficient cost: need {required}, have {remaining}"
+            ),
+            Self::DeadlineTooClose {
+                min_required,
+                remaining,
+            } => write!(
+                f,
+                "deadline too close: need {min_required:?}, have {remaining:?}"
+            ),
+            Self::InsufficientPolls {
+                min_required,
+                remaining,
+            } => write!(
+                f,
+                "insufficient polls: need {min_required}, have {remaining}"
+            ),
